import React, { useState, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  FaUser, 
  FaEdit, 
  FaSave, 
  FaTimes,
  FaPhone,
  FaMapMarkerAlt,
  FaTint,
  FaHeart,
  FaCamera,
  FaUpload,
  FaUserCircle,
  FaBirthdayCake,
  FaVenusMars,
  FaRuler,
  FaWeight,
  FaIdCard
} from 'react-icons/fa';

const Profile = () => {
  const { t } = useTranslation();
  const [isEditing, setIsEditing] = useState(false);
  const [profileImage, setProfileImage] = useState(null);
  const fileInputRef = useRef(null);
  
  // Dummy patient profile data
  const [profileData, setProfileData] = useState({
    name: 'Rajesh Kumar',
    age: 35,
    gender: 'Male',
    phone: '+91 98765 43210',
    address: 'House No. 123, Sector 4, Chandigarh, Punjab - 160012',
    emergency_contact: '+91 87654 32109',
    emergency_contact_name: 'Sunita Kumar (Wife)',
    blood_group: 'B+',
    height: '5\'8"',
    weight: '72 kg',
    medical_history: 'Hypertension (2020), Diabetes Type 2 (2019)',
    insurance_number: 'HLTH123456789',
    date_of_birth: '1988-03-15'
  });

  // Dummy recent appointments
  const recentAppointments = [
    {
      id: 'APT001',
      doctor: 'Dr. Priya Sharma',
      specialty: 'Cardiology',
      date: '2024-01-15',
      time: '10:30 AM',
      status: 'Completed',
      diagnosis: 'Regular checkup - Normal'
    },
    {
      id: 'APT002', 
      doctor: 'Dr. Harpreet Singh',
      specialty: 'General Medicine',
      date: '2024-01-08',
      time: '02:00 PM',
      status: 'Completed',
      diagnosis: 'Fever, prescribed medication'
    },
    {
      id: 'APT003',
      doctor: 'Dr. Sunita Devi',
      specialty: 'Dermatology',
      date: '2024-01-20',
      time: '11:00 AM',
      status: 'Upcoming',
      diagnosis: 'Scheduled'
    }
  ];

  // Dummy medical conditions
  const medicalConditions = [
    {
      condition: 'Hypertension',
      diagnosed: '2020-06-15',
      status: 'Managed',
      medication: 'Amlodipine 5mg daily'
    },
    {
      condition: 'Type 2 Diabetes',
      diagnosed: '2019-11-20',
      status: 'Controlled',
      medication: 'Metformin 500mg twice daily'
    }
  ];

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setProfileData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSave = () => {
    setIsEditing(false);
    // In a real app, this would save to the backend
    console.log('Profile saved:', profileData);
  };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setProfileImage(e.target.result);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-bg-secondary">
      {/* Header - Matching Home Page Style */}
      <div className="bg-gradient-to-r from-primary-color to-primary-dark text-white py-12">
        <div className="container mx-auto px-6 text-center">
          <h1 className="text-4xl font-black mb-4 tracking-tight">
            Patient <span className="text-primary-light">Profile</span>
          </h1>
          <p className="text-xl text-primary-light font-medium">
            {profileData.name} • Age {profileData.age} • {profileData.gender}
          </p>
          <p className="text-primary-light mt-2">
            Manage your personal and medical information
          </p>
        </div>
      </div>

      <div className="container mx-auto px-6 py-8 pb-32">
        <div className="max-w-7xl mx-auto" style={{gap: '0.1cm'}}>
          
          {/* Personal Information Card - Matching Home Page Card Style */}
          <div className="card-elevated" style={{marginBottom: '0.1cm'}}>
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-xl font-bold text-text-primary flex items-center gap-2">
                <FaUser className="text-primary-color" />
                Personal Information
              </h3>
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`btn ${
                  isEditing 
                    ? 'btn-secondary' 
                    : 'btn-primary'
                }`}
              >
                {isEditing ? <FaTimes /> : <FaEdit />}
                {isEditing ? 'Cancel' : 'Edit'}
              </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
              
              {/* Photo Section - Top Left */}
              <div className="lg:col-span-1">
                <div className="text-center">
                  <div className="relative inline-block">
                    <div className="w-32 h-32 mx-auto mb-4 bg-gradient-to-br from-primary-color to-primary-dark rounded-full flex items-center justify-center text-white text-4xl font-bold border border-border-light">
                      {profileImage ? (
                        <img 
                          src={profileImage} 
                          alt="Profile" 
                          className="w-full h-full object-cover rounded-full"
                        />
                      ) : (
                        <FaUserCircle />
                      )}
                    </div>
                    {isEditing && (
                      <div className="absolute -bottom-2 -right-2">
                        <label htmlFor="photo-upload" className="cursor-pointer">
                          <div className="w-10 h-10 bg-primary-color rounded-full flex items-center justify-center text-white hover:bg-primary-dark transition-colors shadow-md border border-border-light">
                            <FaCamera className="text-sm" />
                          </div>
                        </label>
                        <input
                          ref={fileInputRef}
                          id="photo-upload"
                          type="file"
                          accept="image/*"
                          onChange={handleImageUpload}
                          className="hidden"
                        />
                      </div>
                    )}
                  </div>
                  <button
                    onClick={() => {
                      if (fileInputRef.current) {
                        fileInputRef.current.click();
                      }
                    }}
                    className="btn btn-primary text-sm px-4 py-2"
                  >
                    <FaUpload className="mr-2" />
                    Upload Image
                  </button>
                </div>
              </div>

              {/* Personal Details */}
              <div className="lg:col-span-3">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6" style={{rowGap: '0.1cm'}}>
                  
                  <div className="input-group" style={{marginBottom: '0.1cm'}}>
                    <label className="block text-sm font-semibold text-text-primary mb-2">
                      <FaUser className="inline mr-2 text-primary-color" />
                      Full Name
                    </label>
                    {isEditing ? (
                      <input
                        type="text"
                        name="name"
                        value={profileData.name}
                        onChange={handleInputChange}
                        className="input"
                      />
                    ) : (
                      <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light">{profileData.name}</p>
                    )}
                  </div>

                  <div className="input-group" style={{marginBottom: '0.1cm'}}>
                    <label className="block text-sm font-semibold text-text-primary mb-2">
                      <FaBirthdayCake className="inline mr-2 text-primary-color" />
                      Age
                    </label>
                    {isEditing ? (
                      <input
                        type="number"
                        name="age"
                        value={profileData.age}
                        onChange={handleInputChange}
                        className="input"
                      />
                    ) : (
                      <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light">{profileData.age} years</p>
                    )}
                  </div>

                  <div className="input-group" style={{marginBottom: '0.1cm'}}>
                    <label className="block text-sm font-semibold text-text-primary mb-2">
                      <FaVenusMars className="inline mr-2 text-primary-color" />
                      Gender
                    </label>
                    {isEditing ? (
                      <select
                        name="gender"
                        value={profileData.gender}
                        onChange={handleInputChange}
                        className="input"
                      >
                        <option value="Male">Male</option>
                        <option value="Female">Female</option>
                        <option value="Other">Other</option>
                      </select>
                    ) : (
                      <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light">{profileData.gender}</p>
                    )}
                  </div>

                  <div className="input-group" style={{marginBottom: '0.1cm'}}>
                    <label className="block text-sm font-semibold text-text-primary mb-2">
                      <FaPhone className="inline mr-2 text-primary-color" />
                      Contact Number
                    </label>
                    {isEditing ? (
                      <input
                        type="tel"
                        name="phone"
                        value={profileData.phone}
                        onChange={handleInputChange}
                        className="input"
                      />
                    ) : (
                      <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light">{profileData.phone}</p>
                    )}
                  </div>

                  <div className="md:col-span-2 input-group" style={{marginBottom: '0.1cm'}}>
                    <label className="block text-sm font-semibold text-text-primary mb-2">
                      <FaMapMarkerAlt className="inline mr-2 text-primary-color" />
                      Address
                    </label>
                    {isEditing ? (
                      <textarea
                        name="address"
                        value={profileData.address}
                        onChange={handleInputChange}
                        rows="3"
                        className="input resize-none"
                      />
                    ) : (
                      <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light">{profileData.address}</p>
                    )}
                  </div>
                </div>

                {isEditing && (
                  <div className="mt-6 text-right">
                    <button
                      onClick={handleSave}
                      className="btn btn-success"
                    >
                      <FaSave className="mr-2" />
                      Save Changes
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Medical Information Card - Matching Home Page Card Style */}
          <div className="card-elevated" style={{marginBottom: '0.1cm'}}>
            <h3 className="text-xl font-bold text-text-primary mb-6 flex items-center gap-2">
              <FaHeart className="text-red-500" />
              Medical Information
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6" style={{rowGap: '0.1cm'}}>
              
              <div style={{marginBottom: '0.1cm'}}>
                <label className="block text-sm font-semibold text-text-primary mb-2">
                  <FaTint className="inline mr-2 text-red-600" />
                  Blood Group
                </label>
                <div className="text-center">
                  <p className="text-text-primary bg-red-50 px-4 py-3 rounded-lg border border-red-200 font-bold text-lg">{profileData.blood_group}</p>
                </div>
              </div>

              <div style={{marginBottom: '0.1cm'}}>
                <label className="block text-sm font-semibold text-text-primary mb-2">
                  <FaRuler className="inline mr-2 text-primary-color" />
                  Height
                </label>
                <div className="text-center">
                  <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light font-semibold">{profileData.height}</p>
                </div>
              </div>

              <div style={{marginBottom: '0.1cm'}}>
                <label className="block text-sm font-semibold text-text-primary mb-2">
                  <FaWeight className="inline mr-2 text-primary-color" />
                  Weight
                </label>
                <div className="text-center">
                  <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light font-semibold">{profileData.weight}</p>
                </div>
              </div>

              <div style={{marginBottom: '0.1cm'}}>
                <label className="block text-sm font-semibold text-text-primary mb-2">
                  <FaIdCard className="inline mr-2 text-primary-color" />
                  Insurance
                </label>
                <div className="text-center">
                  <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg border border-border-light text-sm font-semibold">{profileData.insurance_number}</p>
                </div>
              </div>
            </div>

            <div className="mt-6" style={{marginTop: '0.1cm'}}>
              <div style={{marginBottom: '0.1cm'}}>
                <label className="block text-sm font-semibold text-text-primary mb-2">
                  <FaPhone className="inline mr-2 text-orange-600" />
                  Emergency Contact
                </label>
                <p className="text-text-primary bg-orange-50 px-4 py-3 rounded-lg border border-orange-200">
                  {profileData.emergency_contact_name} - {profileData.emergency_contact}
                </p>
              </div>
            </div>
          </div>

          {/* Current Medical Conditions - Matching Home Page Card Style */}
          <div className="card-elevated">
            <h3 className="text-xl font-bold text-text-primary mb-6 flex items-center gap-2">
              <FaHeart className="text-primary-color" />
              Current Medical Conditions
            </h3>

            <div className="space-y-4" style={{gap: '0.1cm'}}>
              {medicalConditions.map((condition, index) => (
                <div key={index} className="border border-border-light rounded-lg p-4 hover:shadow-md transition-all duration-300" style={{marginBottom: '0.1cm'}}>
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div>
                      <p className="text-sm font-semibold text-text-secondary">Condition</p>
                      <p className="text-text-primary font-medium">{condition.condition}</p>
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-text-secondary">Diagnosed</p>
                      <p className="text-text-primary">{condition.diagnosed}</p>
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-text-secondary">Status</p>
                      <span className={`inline-block px-2 py-1 rounded-full text-xs font-semibold ${
                        condition.status === 'Controlled' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
                      }`}>
                        {condition.status}
                      </span>
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-text-secondary">Current Medication</p>
                      <p className="text-text-primary text-sm">{condition.medication}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
